import React from 'react';
import {
    Box,
    Button,
    Card,
    CardContent,
    IconButton,
    InputAdornment,
    TextField,
    Stack,
    FormControlLabel,
    Checkbox
} from '@mui/material';
import DeleteIcon from '@mui/icons-material/Delete';
import EditIcon from '@mui/icons-material/Edit';
import { useNavigate } from '@tanstack/react-router';
import { PageContainer } from '@/components/PageContainer';
import { StatusMessage } from '@/components/StatusMessage';
import { ConfirmDialog } from '@/components/ui/ConfirmDialog';
import { EventServices, EventServicesError } from '@/api';
import { ApiComponentStateManager } from '@/lib/api-state';
import { initialStateData, StateData } from '@/store';
import { UpdateEventPayload, EventResult } from '@/types/event.types';
import { CallStatus } from '@/types/api.types';
import { Pathname } from '@/constants/Routes';
import { getSelectedEventContext, saveSelectedEventContext, clearSelectedEventContext } from '@/utils/eventContext';
import { UnixTimestampToDateTimeInput } from '@/utils/common';
import { GetUserId } from '@/utils/token';
import { logger } from '@/utils/logger';
import { getApiError } from '@/utils/apiError';
import { submitButtonStyle } from '@/constants/ThemeConstants';

interface EventEditProps {
    eventId?: string;
}

export const EventEdit: React.FC<EventEditProps> = ({ eventId: propEventId }) => {
    const navigate = useNavigate();
    const currentUserId = React.useMemo(() => GetUserId(), []);
    const [eventId, setEventId] = React.useState<string | null>(propEventId || null);
    
    const [updateState, setUpdateState] = React.useState<StateData<boolean>>(initialStateData<boolean>());
    const [loadState, setLoadState] = React.useState<StateData<EventResult>>(initialStateData<EventResult>());
    const [deleteState, setDeleteState] = React.useState<StateData<boolean>>(initialStateData<boolean>());
    const [deleteDialogOpen, setDeleteDialogOpen] = React.useState(false);
    // Internal form state for UI (using strings for datetime inputs)
    const [formData, setFormData] = React.useState({
        id: '',
        title: '',
        details: '',
        startDateTime: '', // string for datetime-local input
        endDateTime: '',   // string for datetime-local input
        contact: '',
        location: '',
        registrationLink: '',
        locationLink: '',
        isOnlineMeeting: false,
        isRegistrationEnabled: true,
        isCheckinEnabled: true,
        food: '',
        isFoodEnabled: false,
        isAccompanyEnabled: false,
        donation: '',
        donationLink: '',
        owners: '',   // comma-separated user ids
        managers: ''  // comma-separated user ids
    });

    // Sync prop to state
    React.useEffect(() => {
        if (propEventId) setEventId(propEventId);
    }, [propEventId]);

    // Load event data when component mounts
    React.useEffect(() => {
        if (!eventId) return;

        const fetchEventData = async () => {
            try {
                setLoadState(prev => ({ ...prev, status: CallStatus.InProgress }));
                const response = await EventServices.GetEventById(eventId);
                
                if (response.data.status >= 200 && response.data.status < 300 && response.data.result) {
                    const event = response.data.result;
                    setLoadState({
                        data: event,
                        status: CallStatus.Success,
                        httpStatus: response.status,
                        timestamp: new Date(),
                    });
                    
                    // Pre-populate form with event data
                    setFormData({
                        id: eventId,
                        title: event.title,
                        details: event.details,
                        startDateTime: UnixTimestampToDateTimeInput(event.startDateTime),
                        endDateTime: UnixTimestampToDateTimeInput(event.endDateTime),
                        contact: event.contact || '',
                        location: event.location,
                        registrationLink: event.registrationLink || '',
                        locationLink: event.locationLink || '',
                        isOnlineMeeting: event.isOnlineMeeting || false,
                        isRegistrationEnabled: event.isRegistrationEnabled !== undefined ? event.isRegistrationEnabled : true,
                        isCheckinEnabled: event.isCheckinEnabled !== undefined ? event.isCheckinEnabled : true,
                        food: event.food ?? '',
                        isFoodEnabled: event.isFoodEnabled ?? false,
                        isAccompanyEnabled: event.isAccompanyEnabled ?? false,
                        donation: event.donation ?? '',
                        donationLink: event.donationLink ?? '',
                        owners: (event.owners ?? []).filter((id: string) => id !== currentUserId).join(', '),
                        managers: (event.managers ?? []).join(', ')
                    });
                } else {
                    throw new Error('Event not found');
                }
            } catch (error) {
                const info = getApiError(error);
                logger.error('EventEdit', 'Error fetching event data', error);
                setLoadState({
                    data: {} as EventResult,
                    status: CallStatus.Failure,
                    httpStatus: info.httpStatus || 404,
                    timestamp: new Date(),
                    correlationId: info.correlationId,
                });
            }
        };

        fetchEventData();
    }, [eventId]);

    // Navigate back to events list after successful update and update localStorage if needed
    React.useEffect(() => {
        if (updateState.status === CallStatus.Success) {
            // Check if the updated event is the currently selected event in localStorage
            const selectedEvent = getSelectedEventContext();
            if (selectedEvent && selectedEvent.id === eventId) {
                // Update the selected event context with the new data, preserving server-managed fields
                const updatedEvent: EventResult = {
                    ...selectedEvent, // Preserve all original data
                    title: formData.title,
                    details: formData.details,
                    startDateTime: new Date(formData.startDateTime).getTime(),
                    endDateTime: new Date(formData.endDateTime).getTime(),
                    contact: formData.contact,
                    location: formData.location,
                    registrationLink: formData.registrationLink,
                    locationLink: formData.locationLink,
                    isOnlineMeeting: formData.isOnlineMeeting,
                    isRegistrationEnabled: formData.isRegistrationEnabled,
                    isCheckinEnabled: formData.isCheckinEnabled,
                    food: formData.food,
                    isFoodEnabled: formData.isFoodEnabled,
                    owners: (() => {
                        const ids = formData.owners.split(/[\s,]+/).map(x => x.trim()).filter(x => x.length > 0);
                        if (currentUserId && !ids.includes(currentUserId)) ids.unshift(currentUserId);
                        return ids;
                    })(),
                    managers: formData.managers.split(/[\s,]+/).map(x => x.trim()).filter(x => x.length > 0),
                    // Keep original modifiedAt and modifiedBy - these should be set by the server
                };
                saveSelectedEventContext(updatedEvent);
            }
            
            setTimeout(() => {
                navigate({ to: Pathname.Events as string });
            }, 2000);
        }
    }, [updateState.status, navigate, eventId, formData]);

    const handleInputChange = (field: string) => (
        event: React.ChangeEvent<HTMLInputElement>
    ) => {
        const value = event.target.type === 'checkbox' ? event.target.checked : event.target.value;
        setFormData(prev => ({
            ...prev,
            [field]: value
        }));
    };

    const handleSubmit = async (event: React.FormEvent) => {
        event.preventDefault();
        
        if (!eventId) {
            alert('No event ID provided');
            return;
        }

        try {
            // Helper: split a comma/whitespace separated id list
            const splitIds = (s: string): string[] =>
                s.split(/[\s,]+/).map(x => x.trim()).filter(x => x.length > 0);

            // Owners must always include the current user's id (cannot self-remove).
            const extraOwners = splitIds(formData.owners).filter(id => id !== currentUserId);
            const ownerIds = currentUserId ? [currentUserId, ...extraOwners] : extraOwners;

            // Convert form data to API payload with proper types
            const eventPayload: UpdateEventPayload = {
                id: eventId,
                title: formData.title,
                details: formData.details,
                startDateTime: new Date(formData.startDateTime).getTime(), // Convert to number
                endDateTime: new Date(formData.endDateTime).getTime(),     // Convert to number
                contact: formData.contact,
                location: formData.location,
                registrationLink: formData.registrationLink?.trim() ? formData.registrationLink.trim() : undefined,
                locationLink: formData.locationLink?.trim() ? formData.locationLink.trim() : undefined,
                isOnlineMeeting: formData.isOnlineMeeting,
                isRegistrationEnabled: formData.isRegistrationEnabled,
                isCheckinEnabled: formData.isCheckinEnabled,
                food: formData.food,
                isFoodEnabled: formData.isFoodEnabled,
                isAccompanyEnabled: formData.isAccompanyEnabled,
                donation: formData.donation,
                donationLink: formData.donationLink?.trim() ? formData.donationLink.trim() : undefined,
                owners: ownerIds,
                managers: splitIds(formData.managers)
            };
            
            ApiComponentStateManager(EventServices.UpdateEvent(eventPayload), setUpdateState);
        } catch (error) {
            logger.error('EventEdit', 'Error updating event', error);
        }
    };

    const handleCancel = () => {
        navigate({ to: Pathname.Events as string });
    };

    const handleDelete = () => {
        setDeleteDialogOpen(true);
    };

    const handleDeleteConfirm = async () => {
        if (!eventId) return;
        
        setDeleteDialogOpen(false);
        try {
            ApiComponentStateManager(EventServices.DeleteEvent(eventId), setDeleteState);
        } catch (error) {
            logger.error('EventEdit', 'Error deleting event', error);
        }
    };

    const handleDeleteCancel = () => {
        setDeleteDialogOpen(false);
    };

    // Navigate back to events on successful deletion and clear localStorage if needed
    React.useEffect(() => {
        if (deleteState.status === CallStatus.Success) {
            // Check if the deleted event is the currently selected event in localStorage
            const selectedEvent = getSelectedEventContext();
            if (selectedEvent && selectedEvent.id === eventId) {
                // Clear the selected event context since the event was deleted
                clearSelectedEventContext();
            }
            
            setTimeout(() => {
                navigate({ to: Pathname.Events as string });
            }, 2000);
        }
    }, [deleteState.status, navigate, eventId]);

    const isFormValid = () => {
        const baseValidation = formData.title.trim() && 
               formData.details.trim() && 
               formData.startDateTime && 
               formData.endDateTime && 
               formData.contact.trim() &&
               formData.location.trim();
        
        // End must be after Start (backend enforces this in IValidatableObject)
        const dateValidation = !formData.startDateTime || !formData.endDateTime ||
            new Date(formData.endDateTime).getTime() > new Date(formData.startDateTime).getTime();
        
        // If food is enabled, food field must have data
        const foodValidation = !formData.isFoodEnabled || (formData.isFoodEnabled && formData.food.trim());
        
        return baseValidation && dateValidation && foodValidation;
    };

    if (!eventId) {
        return (
            <PageContainer icon={<EditIcon color="primary" />} title="Edit event">
                    <StatusMessage
                        notStartedMessage=""
                        currentStatus={CallStatus.InProgress}
                        correlationId=""
                    />
            </PageContainer>
        );
    }

    // Show loading state while fetching event data
    if (loadState.status === CallStatus.InProgress) {
        return (
            <PageContainer icon={<EditIcon color="primary" />} title="Edit event">
                    <StatusMessage
                        notStartedMessage=""
                        successMessage=""
                        failureMessage=""
                        currentStatus={CallStatus.InProgress}
                        correlationId=""
                    />
            </PageContainer>
        );
    }

    // Show error if event not found or fetch failed
    if (loadState.status === CallStatus.Failure) {
        return (
            <PageContainer icon={<EditIcon color="primary" />} title="Edit event">
                    <StatusMessage
                        notStartedMessage=""
                        successMessage=""
                        failureMessage={EventServicesError.GetEventsError(loadState.httpStatus)}
                        currentStatus={CallStatus.Failure}
                        correlationId={loadState.correlationId}
                    />
                    <Button onClick={handleCancel} variant="outlined" sx={{ mt: 2 }}>
                        Back to Events
                    </Button>
            </PageContainer>
        );
    }

    return (
        <>
        <PageContainer
            icon={<EditIcon color="primary" />}
            title="Edit event"
            subtitle="Update event details and settings."
        >
            <Card sx={{ mb: 2 }}>
                <CardContent>
            <form onSubmit={handleSubmit}>
                <Stack spacing={2}>
                            <TextField
                                fullWidth
                                label="Event Title"
                                value={formData.title}
                                onChange={handleInputChange('title')}
                                required
                                variant="outlined"
                                placeholder="Enter event title"
                            />

                            <TextField
                                fullWidth
                                label="Event Details"
                                value={formData.details}
                                onChange={handleInputChange('details')}
                                required
                                multiline
                                rows={4}
                                variant="outlined"
                                placeholder="Enter event description"
                            />

                            <Stack direction={{ xs: 'column', sm: 'row' }} spacing={2}>
                                <TextField
                                    fullWidth
                                    label="Start Date & Time"
                                    type="datetime-local"
                                    value={formData.startDateTime}
                                    onChange={handleInputChange('startDateTime')}
                                    required
                                    variant="outlined"
                                    slotProps={{ inputLabel: { shrink: true } }}
                                />

                                <TextField
                                    fullWidth
                                    label="End Date & Time"
                                    type="datetime-local"
                                    value={formData.endDateTime}
                                    onChange={handleInputChange('endDateTime')}
                                    required
                                    variant="outlined"
                                    slotProps={{ inputLabel: { shrink: true } }}
                                />
                            </Stack>

                            <TextField
                                fullWidth
                                label="Contact"
                                value={formData.contact}
                                onChange={handleInputChange('contact')}
                                required
                                variant="outlined"
                                placeholder="Enter contact details for the event"
                            />

                            <TextField
                                fullWidth
                                label="Location"
                                value={formData.location}
                                onChange={handleInputChange('location')}
                                required
                                variant="outlined"
                                placeholder="Enter event location"
                            />

                            <TextField
                                fullWidth
                                label="Registration Link (Optional)"
                                value={formData.registrationLink}
                                onChange={handleInputChange('registrationLink')}
                                variant="outlined"
                                placeholder="https://example.com/register"
                                type="url"
                                helperText="Link for external event registration"
                            />

                            <TextField
                                fullWidth
                                label="Location Link (Optional)"
                                value={formData.locationLink}
                                onChange={handleInputChange('locationLink')}
                                variant="outlined"
                                placeholder="https://maps.google.com/..."
                                type="url"
                                helperText="Link to location (e.g., Google Maps, venue website)"
                            />

                            <FormControlLabel
                                control={
                                    <Checkbox
                                        checked={formData.isFoodEnabled}
                                        onChange={handleInputChange('isFoodEnabled')}
                                    />
                                }
                                label="Enable Food Preferences"
                            />

                            {formData.isFoodEnabled && (
                                <TextField
                                    fullWidth
                                    label="Food Preferences"
                                    value={formData.food}
                                    onChange={handleInputChange('food')}
                                    required
                                    variant="outlined"
                                    placeholder="e.g., Vegetarian, Vegan, Gluten-free, Halal"
                                    helperText="Enter comma-separated food preferences for attendees (required)"
                                    multiline
                                    rows={2}
                                />
                            )}

                            <FormControlLabel
                                control={
                                    <Checkbox
                                        checked={formData.isAccompanyEnabled}
                                        onChange={handleInputChange('isAccompanyEnabled')}
                                    />
                                }
                                label="Allow additional guests"
                            />

                            <TextField
                                fullWidth
                                label="Donation Information (Optional)"
                                value={formData.donation}
                                onChange={handleInputChange('donation')}
                                variant="outlined"
                                placeholder="Describe donation details or purpose"
                                helperText="Information about donations for this event"
                                multiline
                                rows={3}
                            />

                            <TextField
                                fullWidth
                                label="Donation Link (Optional)"
                                value={formData.donationLink}
                                onChange={handleInputChange('donationLink')}
                                variant="outlined"
                                placeholder="https://example.com/donate"
                                type="url"
                                helperText="Link for donation processing or payment"
                            />

                            <TextField
                                fullWidth
                                label="Owners (User IDs)"
                                value={formData.owners}
                                onChange={handleInputChange('owners')}
                                variant="outlined"
                                placeholder="Add more owner user IDs, comma separated"
                                helperText="Your own ID is locked. Add more owner IDs after it."
                                multiline
                                rows={2}
                                slotProps={{
                                    input: {
                                        startAdornment: currentUserId ? (
                                            <InputAdornment position="start" sx={{ alignSelf: 'flex-start', mt: 1.25, mr: 0 }}>
                                                <Box
                                                    component="span"
                                                    sx={{
                                                        display: 'inline-block',
                                                        px: 1,
                                                        py: 0.25,
                                                        bgcolor: 'action.disabledBackground',
                                                        color: 'text.disabled',
                                                        borderRadius: 1,
                                                        fontFamily: 'monospace',
                                                        fontSize: '0.85rem',
                                                        userSelect: 'none',
                                                    }}
                                                >
                                                    {currentUserId},
                                                </Box>
                                            </InputAdornment>
                                        ) : undefined,
                                    },
                                }}
                            />

                            <TextField
                                fullWidth
                                label="Managers (User IDs)"
                                value={formData.managers}
                                onChange={handleInputChange('managers')}
                                variant="outlined"
                                placeholder="userId1, userId2, ..."
                                helperText="Comma-separated user IDs allowed to check-in attendees only"
                                multiline
                                rows={2}
                            />

                            <Stack direction={{ xs: 'column', sm: 'row' }} spacing={2} sx={{ alignItems: 'flex-start' }}>
                                <FormControlLabel
                                    control={
                                        <Checkbox
                                            checked={formData.isOnlineMeeting}
                                            onChange={handleInputChange('isOnlineMeeting')}
                                        />
                                    }
                                    label="Online Meeting"
                                />
                                
                                <FormControlLabel
                                    control={
                                        <Checkbox
                                            checked={formData.isRegistrationEnabled}
                                            onChange={handleInputChange('isRegistrationEnabled')}
                                        />
                                    }
                                    label="Registration Enabled"
                                />
                                
                                <FormControlLabel
                                    control={
                                        <Checkbox
                                            checked={formData.isCheckinEnabled}
                                            onChange={handleInputChange('isCheckinEnabled')}
                                        />
                                    }
                                    label="Check-in Enabled"
                                />
                            </Stack>

                            <Stack direction="row" spacing={2} sx={{ pt: 2, justifyContent: 'space-between', alignItems: 'center' }}>
                                <Stack direction="row" spacing={2}>
                                    <Button
                                        type="submit"
                                        variant="contained"
                                        disabled={!isFormValid() || updateState.status === CallStatus.InProgress}
                                        style={submitButtonStyle}
                                    >
                                        {updateState.status === CallStatus.InProgress ? 'Updating...' : 'Update'}
                                    </Button>
                                    
                                    <Button
                                        variant="outlined"
                                        onClick={handleCancel}
                                        disabled={updateState.status === CallStatus.InProgress || deleteState.status === CallStatus.InProgress}
                                    >
                                        Cancel
                                    </Button>
                                </Stack>

                                {/* Delete Button */}
                                <IconButton
                                    onClick={handleDelete}
                                    color="error"
                                    size="medium"
                                    title="Delete Event"
                                    disabled={updateState.status === CallStatus.InProgress || deleteState.status === CallStatus.InProgress}
                                    sx={{
                                        '&:hover': {
                                            backgroundColor: 'error.light',
                                            color: 'white'
                                        }
                                    }}
                                >
                                    <DeleteIcon />
                                </IconButton>
                            </Stack>
                    </Stack>
                </form>

                {/* Status Messages */}
                <StatusMessage
                        notStartedMessage=""
                        successMessage="Event updated successfully! Redirecting to events list..."
                        failureMessage={EventServicesError.UpdateEventError(updateState.httpStatus)}
                        currentStatus={updateState.status}
                        correlationId={updateState.correlationId}
                    />

                {/* Delete Status Message */}
                {deleteState.status !== CallStatus.NotStarted && (
                    <Box sx={{ mt: 2 }}>
                        <StatusMessage
                            notStartedMessage=""
                            successMessage="Event deleted successfully! Redirecting to events list..."
                            failureMessage={EventServicesError.DeleteEventError(deleteState.httpStatus)}
                            currentStatus={deleteState.status}
                            correlationId={deleteState.correlationId}
                        />
                    </Box>
                )}
                </CardContent>
            </Card>
        </PageContainer>

            {/* Delete Confirmation Dialog */}
            <ConfirmDialog
                open={deleteDialogOpen}
                onCancel={handleDeleteCancel}
                onConfirm={handleDeleteConfirm}
                title="Delete Event"
                description={`Are you sure you want to delete the event "${formData.title}"? This action cannot be undone.`}
                confirmLabel="Delete"
                tone="error"
                busy={deleteState.status === CallStatus.InProgress}
                busyLabel="Deleting..."
            />
        </>
    );
};